import React from "react";
import { Hammer, Home, Wrench, ArrowUpRight } from "lucide-react";

const services = [
  {
    icon: Wrench,
    title: "Full Structural Guts",
    body: "Complete interior tear-downs and structural guts. We handle complex load-bearing wall removals, reframing, and comprehensive mechanical rough-ins to prepare the canvas.",
    img: "https://images.unsplash.com/photo-1768677903496-becc4be07258?crop=entropy&cs=srgb&fm=jpg&ixid=M3w3NDk1ODB8MHwxfHNlYXJjaHwxfHxjb21tZXJjaWFsJTIwY29uc3RydWN0aW9uJTIwc2l0ZXxlbnwwfHx8fDE3ODA5MjQ1MjJ8MA&ixlib=rb-4.1.0&q=85",
  },
  {
    icon: Hammer,
    title: "Interior Redesign & Remodelling",
    body: "Whole-home remodelling and interior renovations. Transforming existing footprints with millimeter-tight precision, custom millwork, and premium high-end finishes.",
    img: "https://images.unsplash.com/photo-1628744876497-eb30460be9f6?crop=entropy&cs=srgb&fm=jpg&ixid=M3w3NDk1Nzh8MHwxfHNlYXJjaHwxfHxtb2Rlcm4lMjBpbnRlcmlvciUyMGx1eHVyeSUyMHJlbm92YXRpb258ZW58MHx8fHwxNzgwOTI0NTIyfDA&ixlib=rb-4.1.0&q=85",
  },
  {
    icon: Home,
    title: "Exterior Transformations",
    body: "Elevating curb appeal while fortifying structural integrity. From architectural window installations and contemporary siding to complete outdoor living extensions.",
    img: "https://images.unsplash.com/photo-1574120583586-de8847ae992c?crop=entropy&cs=srgb&fm=jpg&ixid=M3w4NjAzMjh8MHwxfHNlYXJjaHwxfHxvdXRkb29yJTIwZGVjayUyMGhvdXNlJTIwZXh0ZXJpb3J8ZW58MHx8fHwxNzgwOTI0NTQxfDA&ixlib=rb-4.1.0&q=85",
  },
];

export default function Services() {
  return (
    <section
      id="services"
      data-testid="services-section"
      className="bg-brand-surface py-28 md:py-40"
    >
      <div className="max-w-7xl mx-auto px-6 md:px-10">
        <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-8 mb-16 md:mb-24">
          <div className="reveal max-w-2xl">
            <div className="flex items-center gap-3 mb-6">
              <span className="block w-10 h-px bg-brand-accent" />
              <span className="text-xs tracking-[0.28em] uppercase text-brand-smoke font-medium">
                Our Capabilities
              </span>
            </div>
            <h2
              data-testid="services-headline"
              className="font-display text-4xl md:text-5xl lg:text-6xl font-medium text-brand-ink tracking-tighter leading-[1.05]"
            >
              Built from the studs up.
            </h2>
          </div>
          {/* I filled in this empty paragraph tag with a great sub-headline! */}
          <p className="text-base md:text-lg text-brand-smoke max-w-sm reveal pb-2">
            We bring enterprise-grade discipline to residential builds. Whether we are stripping a property to its bones or executing a flawless interior redesign.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:gap-8">
          {services.map((s, i) => {
            const Icon = s.icon;
            return (
              <article
                key={s.title}
                data-testid={`service-card-${i}`}
                className="reveal group bg-white border border-brand-line p-8 md:p-10 flex flex-col transition-all duration-500 hover:border-brand-ink hover:-translate-y-1"
              >
                <div className="aspect-[4/3] w-full overflow-hidden mb-8 bg-brand-surface2">
                  <img
                    src={s.img}
                    alt={s.title}
                    loading="lazy"
                    className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
                  />
                </div>
                <div className="flex items-center justify-between mb-5">
                  <Icon size={22} className="text-brand-ink" strokeWidth={1.5} />
                  <span className="text-xs tracking-widest uppercase text-brand-muted">
                    0{i + 1}
                  </span>
                </div>
                <h3 className="font-display text-2xl md:text-[26px] font-medium text-brand-ink leading-tight">
                  {s.title}
                </h3>
                <p className="mt-4 text-base leading-relaxed text-brand-smoke flex-1">
                  {s.body}
                </p>
                <a
                  href="#contact"
                  data-testid={`service-cta-${i}`}
                  className="mt-8 inline-flex items-center gap-2 text-sm font-medium text-brand-ink group-hover:text-brand-accent transition-colors"
                >
                  Discuss your scope
                  <ArrowUpRight
                    size={16}
                    className="transition-transform duration-300 group-hover:translate-x-0.5 group-hover:-translate-y-0.5"
                  />
                </a>
              </article>
            );
          })}
        </div>
      </div>
    </section>
  );
}
